import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, ExternalLink, Zap, Terminal, ChevronUp, ChevronDown, Radio } from 'lucide-react';

const DATABASE = [
  {
    id: 1,
    title: "Silva Abogados — Inicio",
    url: "https://123.com",
    date: "2025-04-10",
    parents: ["https://google.com/search?q=silva+abogados", "https://directoriolegales.com/firmas"],
    children: ["https://123.com/about", "https://123.com/servicios", "https://123.com/contacto"],
  },
  {
    id: 2,
    title: "Silva Abogados — Servicios Legales",
    url: "https://123.com/servicios",
    date: "2025-03-22",
    parents: ["https://123.com", "https://123.com/about"],
    children: ["https://123.com/servicios/civil", "https://123.com/servicios/penal", "https://123.com/servicios/corporativo"],
  },
  {
    id: 3,
    title: "Silva Abogados — Contacto",
    url: "https://123.com/contacto",
    date: "2025-02-18",
    parents: ["https://123.com"],
    children: [],
  },
  {
    id: 4,
    title: "Silva Abogados — Sobre Nosotros",
    url: "https://123.com/about",
    date: "2025-01-05",
    parents: ["https://123.com"],
    children: ["https://123.com/equipo", "https://123.com/historia"],
  },
  {
    id: 5,
    title: "Silva Abogados — Derecho Civil",
    url: "https://123.com/servicios/civil",
    date: "2024-12-14",
    parents: ["https://123.com/servicios"],
    children: ["https://123.com/servicios/civil/divorcio", "https://123.com/servicios/civil/contratos"],
  },
  {
    id: 6,
    title: "Silva Abogados — Derecho Penal",
    url: "https://123.com/servicios/penal",
    date: "2024-11-30",
    parents: ["https://123.com/servicios"],
    children: ["https://123.com/servicios/penal/defensa"],
  },
  {
    id: 7,
    title: "Silva Abogados — Derecho Corporativo",
    url: "https://123.com/servicios/corporativo",
    date: "2024-10-20",
    parents: ["https://123.com/servicios"],
    children: ["https://123.com/servicios/corporativo/contratos"],
  },
];

export default function HackerSearch() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [lastQuery, setLastQuery] = useState('');
  const [phase, setPhase] = useState('idle'); // idle | loading | done
  const [blink, setBlink] = useState(true);
  const [headerText, setHeaderText] = useState('');
  const fullHeader = 'COMP4321X::SEARCH_ENGINE';
  const inputRef = useRef(null);

  // Blinking cursor
  useEffect(() => {
    const t = setInterval(() => setBlink(b => !b), 530);
    return () => clearInterval(t);
  }, []);

  // Typewriter header
  useEffect(() => {
    let i = 0;
    const t = setInterval(() => {
      setHeaderText(fullHeader.slice(0, i + 1));
      i++;
      if (i >= fullHeader.length) clearInterval(t);
    }, 45);
    return () => clearInterval(t);
  }, []);

  const doSearch = (q) => {
    if (!q.trim()) return;
    setPhase('loading');
    setTimeout(() => {
      const lower = q.toLowerCase();
      const filtered = DATABASE.filter(r =>
        r.title.toLowerCase().includes(lower) ||
        r.url.toLowerCase().includes(lower)
      );
      setResults(filtered.length > 0 ? filtered : DATABASE);
      setLastQuery(q);
      setPhase('done');
    }, 700);
  };

  const handleSearch = () => doSearch(query);

  const handleSimilar = (title) => {
    const kw = title.replace(/Silva Abogados —\s*/i, '').trim().split(' ')[0];
    setQuery(kw);
    doSearch(kw);
  };

  return (
    <div
      className="min-h-screen bg-black text-green-400 font-mono relative overflow-hidden"
    >
      {/* Scanlines */}
      <div
        className="pointer-events-none fixed inset-0 z-50 opacity-10"
        style={{
          backgroundImage:
            'repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,1) 3px, rgba(0,0,0,1) 4px)',
        }}
      />

      {/* Ambient glow */}
      <div className="pointer-events-none fixed top-0 left-0 w-full h-64 opacity-5"
        style={{ background: 'radial-gradient(ellipse at 50% 0%, #00ff41 0%, transparent 70%)' }} />

      <div className="max-w-3xl mx-auto px-4 py-8 relative z-10">

        {/* ── HEADER ── */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.4 }}
          className="mb-10"
        >
          <div className="flex items-center gap-2 mb-3">
            <Radio size={12} className="text-green-600 animate-pulse" />
            <span className="text-green-800 text-xs tracking-widest uppercase">
              SYS // CONNECTED TO: https://123.com
            </span>
          </div>

          <div className="flex items-end gap-2">
            <h1 className="text-3xl font-bold text-green-300 tracking-tight leading-none">
              {headerText}
            </h1>
            <span
              className="text-green-400 text-2xl leading-none mb-px transition-opacity"
              style={{ opacity: blink ? 1 : 0 }}
            >▋</span>
          </div>

          <div className="flex items-center gap-4 mt-2">
            <span className="text-green-900 text-xs tracking-widest">
              // v2.4.1 &nbsp;|&nbsp; INDEX SIZE: {DATABASE.length} DOCS &nbsp;|&nbsp; DOMAIN: SILVA_LEGAL
            </span>
          </div>

          <div className="mt-3 h-px bg-green-950" />
        </motion.div>

        {/* ── SEARCH BAR ── */}
        <div className="mb-8">
          <div className="flex">
            <div
              className="flex-1 flex items-center border border-green-900 bg-zinc-950 px-3 py-3
                         focus-within:border-green-500 transition-colors duration-200"
              style={{ boxShadow: 'inset 0 0 12px rgba(0,255,65,0.03)' }}
            >
              <Terminal size={13} className="text-green-700 mr-2 flex-shrink-0" />
              <span className="text-green-600 mr-1 text-sm select-none">$&gt;&nbsp;</span>
              <input
                ref={inputRef}
                className="flex-1 bg-transparent text-green-200 outline-none placeholder-green-900
                           text-sm tracking-wide caret-green-400 min-w-0"
                placeholder="query..."
                value={query}
                onChange={e => setQuery(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleSearch()}
                autoFocus
              />
            </div>
            <motion.button
              whileTap={{ scale: 0.96 }}
              onClick={handleSearch}
              className="border border-l-0 border-green-900 px-5 py-3 text-green-600
                         hover:bg-green-950 hover:text-green-200 hover:border-green-500
                         transition-colors duration-200 text-xs tracking-widest
                         flex items-center gap-2 flex-shrink-0"
            >
              <Search size={13} />
              EXEC
            </motion.button>
          </div>
          <p className="text-green-950 text-xs mt-2 tracking-wide">
            // ENTER to execute &nbsp;·&nbsp; partial match supported
          </p>
        </div>

        {/* ── LOADING ── */}
        <AnimatePresence>
          {phase === 'loading' && (
            <motion.div
              key="loading"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="text-green-700 text-xs tracking-widest mb-6 animate-pulse"
            >
              &gt;&gt; SCANNING INDEX... TRAVERSING GRAPH... PLEASE WAIT_
            </motion.div>
          )}
        </AnimatePresence>

        {/* ── RESULT COUNT ── */}
        <AnimatePresence>
          {phase === 'done' && (
            <motion.div
              key="count"
              initial={{ opacity: 0, y: -4 }}
              animate={{ opacity: 1, y: 0 }}
              className="mb-6"
            >
              <p className="text-xs tracking-wide">
                <span className="text-green-700">&gt;&nbsp;</span>
                <span className="text-green-600">Found&nbsp;</span>
                <span className="text-green-300 font-bold">{results.length}</span>
                <span className="text-green-600"> document(s) for query:&nbsp;</span>
                <span className="text-green-400">"{lastQuery}"</span>
              </p>
              <div className="h-px bg-green-950 mt-3" />
            </motion.div>
          )}
        </AnimatePresence>

        {/* ── RESULTS ── */}
        <AnimatePresence>
          {phase === 'done' &&
            results.map((r, i) => (
              <motion.div
                key={r.id}
                initial={{ opacity: 0, x: -16 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: i * 0.06, duration: 0.25 }}
                className="mb-5 border border-green-950 bg-zinc-950 group
                           hover:border-green-800 transition-colors duration-200"
                style={{ boxShadow: '0 0 0 0 transparent' }}
              >
                {/* Card header bar */}
                <div className="flex items-center justify-between px-4 py-2
                                border-b border-green-950 group-hover:border-green-900
                                transition-colors bg-black">
                  <div className="flex items-center gap-2">
                    <span className="text-green-900 text-xs">▸</span>
                    <span className="text-green-800 text-xs tracking-widest">
                      REC_{String(r.id).padStart(3, '0')}
                    </span>
                  </div>
                  <span className="text-green-900 text-xs">{r.date}</span>
                </div>

                <div className="p-4">
                  {/* Title */}
                  <p className="text-green-200 font-bold text-sm tracking-wide mb-2 leading-snug">
                    {r.title}
                  </p>

                  {/* URL */}
                  <div className="flex items-center gap-1.5 mb-4">
                    <ExternalLink size={11} className="text-green-800 flex-shrink-0" />
                    <a
                      href={r.url}
                      target="_blank"
                      rel="noreferrer"
                      className="text-green-600 text-xs hover:text-green-300 transition-colors
                                 underline decoration-green-900 hover:decoration-green-600 truncate"
                    >
                      {r.url}
                    </a>
                  </div>

                  {/* Parents & Children */}
                  <div className="grid grid-cols-1 gap-3 mb-4 sm:grid-cols-2">
                    {/* Parents */}
                    <div className="border border-green-950 p-3">
                      <div className="flex items-center gap-1.5 mb-2">
                        <ChevronUp size={11} className="text-green-700" />
                        <span className="text-green-700 text-xs tracking-widest uppercase">
                          Parents
                        </span>
                        <span className="text-green-900 text-xs">
                          [{r.parents.length}]
                        </span>
                      </div>
                      {r.parents.length > 0 ? (
                        <div className="space-y-1 pl-2 border-l border-green-950">
                          {r.parents.map((p, j) => (
                            <a
                              key={j}
                              href={p}
                              target="_blank"
                              rel="noreferrer"
                              className="block text-green-900 text-xs hover:text-green-600
                                         transition-colors truncate"
                            >
                              {p}
                            </a>
                          ))}
                        </div>
                      ) : (
                        <span className="text-green-950 text-xs pl-2">NULL</span>
                      )}
                    </div>

                    {/* Children */}
                    <div className="border border-green-950 p-3">
                      <div className="flex items-center gap-1.5 mb-2">
                        <ChevronDown size={11} className="text-green-700" />
                        <span className="text-green-700 text-xs tracking-widest uppercase">
                          Children
                        </span>
                        <span className="text-green-900 text-xs">
                          [{r.children.length}]
                        </span>
                      </div>
                      {r.children.length > 0 ? (
                        <div className="space-y-1 pl-2 border-l border-green-950">
                          {r.children.map((c, j) => (
                            <a
                              key={j}
                              href={c}
                              target="_blank"
                              rel="noreferrer"
                              className="block text-green-900 text-xs hover:text-green-600
                                         transition-colors truncate"
                            >
                              {c}
                            </a>
                          ))}
                        </div>
                      ) : (
                        <span className="text-green-950 text-xs pl-2">NULL</span>
                      )}
                    </div>
                  </div>

                  {/* Find Similar Button */}
                  <motion.button
                    whileHover={{ scale: 1.02 }}
                    whileTap={{ scale: 0.97 }}
                    onClick={() => handleSimilar(r.title)}
                    className="flex items-center gap-1.5 border border-green-900 px-3 py-1.5
                               text-green-800 text-xs tracking-widest hover:border-green-600
                               hover:text-green-400 hover:bg-green-950 transition-all duration-200"
                  >
                    <Zap size={10} />
                    find similar pages
                  </motion.button>
                </div>
              </motion.div>
            ))}
        </AnimatePresence>

        {/* ── EMPTY STATE ── */}
        {phase === 'idle' && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1 }}
            className="text-center py-16"
          >
            <p className="text-green-950 text-xs tracking-widest">
              // AWAITING INPUT — TYPE A QUERY AND PRESS EXEC
            </p>
          </motion.div>
        )}

        {/* ── FOOTER ── */}
        <div className="mt-14 border-t border-green-950 pt-4">
          <p className="text-green-950 text-xs tracking-widest">
            &gt; SILVA_SEARCH // INDEXED: {DATABASE.length} DOCUMENTS // © 2025
          </p>
        </div>
      </div>
    </div>
  );
}
